import type { CareerQuestion } from "./rrt-questions";

export const sonographyQuestionsBatch7: CareerQuestion[] = [
  { id: "sono-506", stem: "The TI-RADS classification system is used for:", options: ["Stratifying thyroid nodule risk and guiding biopsy decisions","Classifying liver lesions","Grading carotid stenosis","Staging breast cancer"], correctIndex: 0, rationale: "ACR TI-RADS assigns points based on composition, echogenicity, shape, margin, and echogenic foci. Higher scores indicate greater suspicion and guide FNA recommendations.", difficulty: 2, category: "Small Parts & Superficial", topic: "Thyroid" },
  { id: "sono-507", stem: "A thyroid nodule with peripheral eggshell calcification is:", options: ["Indeterminate but less suspicious than microcalcifications","Highly suspicious for malignancy","Always benign","An indication for immediate surgery"], correctIndex: 0, rationale: "Peripheral/eggshell calcification is less suspicious than microcalcifications. Microcalcifications (punctate echogenic foci) are more strongly associated with papillary thyroid carcinoma.", difficulty: 3, category: "Small Parts & Superficial", topic: "Thyroid" },
  { id: "sono-508", stem: "The normal thyroid isthmus measures:", options: ["Less than 3mm in AP diameter","Greater than 10mm","5-8mm","Greater than 15mm"], correctIndex: 0, rationale: "Normal thyroid isthmus is typically <3mm AP. Enlargement may indicate thyroiditis, goiter, or mass lesion.", difficulty: 2, category: "Small Parts & Superficial", topic: "Thyroid" },
  { id: "sono-509", stem: "Hashimoto's thyroiditis on ultrasound typically appears as:", options: ["Diffusely heterogeneous, hypoechoic gland with fibrous septations creating a pseudonodular pattern","Homogeneous hyperechoic gland","Solitary calcified nodule","Normal-appearing gland"], correctIndex: 0, rationale: "Hashimoto's shows diffuse heterogeneity, hypoechogenicity due to lymphocytic infiltration, and fibrous bands creating a pseudonodular appearance. The gland may be enlarged or atrophic.", difficulty: 3, category: "Small Parts & Superficial", topic: "Thyroid" },
  { id: "sono-510", stem: "The BI-RADS ultrasound assessment category 3 means:", options: ["Probably benign — short-interval follow-up recommended","Highly suspicious for malignancy","Incomplete assessment","Negative — routine screening"], correctIndex: 0, rationale: "BI-RADS 3: probably benign (<2% malignancy risk). Typically recommends 6-month follow-up. Common for solid masses with benign features (oval, circumscribed, parallel orientation).", difficulty: 2, category: "Small Parts & Superficial", topic: "Breast" },
  { id: "sono-511", stem: "A breast mass that is taller than wide (anti-parallel orientation) is suspicious because:", options: ["It suggests infiltrative growth crossing tissue planes, which is characteristic of malignancy","It indicates a fluid-filled cyst","It represents normal breast tissue variation","It always indicates fibroadenoma"], correctIndex: 0, rationale: "Taller-than-wide shape indicates growth perpendicular to tissue planes, suggesting an infiltrative process. Benign masses tend to grow parallel to tissue planes (wider than tall).", difficulty: 3, category: "Small Parts & Superficial", topic: "Breast" },
  { id: "sono-512", stem: "A fibroadenoma typically appears on breast ultrasound as:", options: ["Well-circumscribed, oval, homogeneous, hypoechoic solid mass with parallel orientation","Irregular spiculated mass with posterior shadowing","Complex cystic mass with thick septations","Hyperechoic mass with calcifications"], correctIndex: 0, rationale: "Fibroadenomas are the most common benign breast tumors in young women. They appear well-defined, oval/lobulated, homogeneous, hypoechoic, and oriented parallel to the skin.", difficulty: 1, category: "Small Parts & Superficial", topic: "Breast" },
  { id: "sono-513", stem: "Acute epididymitis on scrotal ultrasound shows:", options: ["Enlarged, hyperechoic epididymis with increased color Doppler flow","Decreased blood flow to the epididymis","Echogenic mass within the testis","Normal epididymis without changes"], correctIndex: 0, rationale: "Acute epididymitis shows epididymal enlargement (usually starting at tail), hypoechoic or hyperechoic changes, and markedly increased vascularity on color Doppler. Associated reactive hydrocele is common.", difficulty: 2, category: "Small Parts & Superficial", topic: "Scrotal" },
  { id: "sono-514", stem: "Testicular torsion on ultrasound demonstrates:", options: ["Absent or decreased intratesticular blood flow on color Doppler","Increased blood flow to the affected testis","Normal symmetric blood flow","Hyperechoic testis with posterior enhancement"], correctIndex: 0, rationale: "Torsion causes spermatic cord twisting, compromising blood supply. Color Doppler shows absent/decreased flow in the affected testis. It is a surgical emergency requiring detorsion within 6 hours.", difficulty: 1, category: "Small Parts & Superficial", topic: "Scrotal" },
  { id: "sono-515", stem: "A varicocele is best demonstrated:", options: ["With the patient performing Valsalva maneuver in the upright position, showing dilated pampiniform plexus veins >3mm","In the supine position without provocation","During deep inspiration only","With the patient in Trendelenburg position"], correctIndex: 0, rationale: "Varicoceles are dilated pampiniform plexus veins (>3mm). Valsalva and upright positioning increase abdominal pressure, accentuating venous dilation. More common on the left side (95%).", difficulty: 2, category: "Small Parts & Superficial", topic: "Scrotal" },
  { id: "sono-516", stem: "The ALARA principle in ultrasound refers to:", options: ["As Low As Reasonably Achievable — minimizing ultrasound exposure while obtaining diagnostic quality images","A specific transducer cleaning protocol","An image optimization technique","A billing and coding standard"], correctIndex: 0, rationale: "ALARA applies to ultrasound: use the lowest output power, shortest scan time, and minimal exposure to achieve diagnostic information. Thermal and mechanical indices should be monitored.", difficulty: 1, category: "Patient Care & Safety", topic: "Safety Principles" },
  { id: "sono-517", stem: "The mechanical index (MI) on ultrasound equipment indicates:", options: ["The likelihood of cavitation (mechanical bioeffects) in tissue","The thermal effect of the ultrasound beam","The image frame rate","The depth of penetration"], correctIndex: 0, rationale: "MI relates to peak rarefactional pressure and indicates cavitation risk. MI <0.7 is considered safe. Higher MI increases risk of mechanical tissue damage, particularly with contrast agents.", difficulty: 2, category: "Patient Care & Safety", topic: "Safety Principles" },
  { id: "sono-518", stem: "The thermal index (TI) indicates:", options: ["The potential for temperature elevation in tissue due to ultrasound exposure","The mechanical damage potential","The frequency of the ultrasound beam","The acoustic impedance of tissue"], correctIndex: 0, rationale: "TI estimates potential tissue temperature rise. TI of 1.0 predicts a 1°C rise. Three subtypes exist: TIS (soft tissue), TIB (bone), TIC (cranial). Keep TI as low as practicable.", difficulty: 2, category: "Patient Care & Safety", topic: "Safety Principles" },
  { id: "sono-519", stem: "Proper infection control for ultrasound transducers between patients includes:", options: ["Low-level disinfection with approved wipes for external use; high-level disinfection for endocavitary probes after each patient","Rinsing with water only","No cleaning is required between patients","Autoclaving after every examination"], correctIndex: 0, rationale: "External transducers require low-level disinfection. Endocavitary (TV, TE) and intraoperative probes require high-level disinfection (HLD) after each use. Single-use probe covers should also be used.", difficulty: 2, category: "Patient Care & Safety", topic: "Infection Control" },
  { id: "sono-520", stem: "Proper body mechanics for the sonographer are important to prevent:", options: ["Work-related musculoskeletal disorders (WRMSDs) including shoulder, wrist, and back injuries","Radiation exposure","Electrical shock","Patient falls"], correctIndex: 0, rationale: "Sonographers have high rates of WRMSDs due to repetitive scanning motions, awkward postures, and sustained pressure. Proper ergonomics include adjustable equipment, neutral positioning, and regular breaks.", difficulty: 1, category: "Patient Care & Safety", topic: "Ergonomics" },
  { id: "sono-521", stem: "When scanning a patient who reports a latex allergy, the sonographer should:", options: ["Use non-latex probe covers and gloves","Proceed with standard latex supplies","Cancel the examination","Use powder-free latex products only"], correctIndex: 0, rationale: "Latex allergy can cause reactions ranging from contact dermatitis to anaphylaxis. Non-latex alternatives (nitrile, polyurethane) must be used for all supplies contacting the patient.", difficulty: 1, category: "Patient Care & Safety", topic: "Patient Safety" },
  { id: "sono-522", stem: "A patient becomes diaphoretic and hypotensive during a sonographic examination. The sonographer should first:", options: ["Stop the examination, position the patient safely, call for medical assistance","Continue the scan to complete the study","Document findings and schedule a follow-up","Increase the room temperature"], correctIndex: 0, rationale: "Vasovagal or other acute reactions require immediate response: stop scanning, ensure patient safety (lower exam table, legs elevated), call for help, monitor vital signs.", difficulty: 1, category: "Patient Care & Safety", topic: "Emergency Response" },
  { id: "sono-523", stem: "Spatial resolution in ultrasound is divided into:", options: ["Axial, lateral, and elevational (slice thickness) resolution","Only axial and lateral","Only depth resolution","Temporal and spatial only"], correctIndex: 0, rationale: "Spatial resolution has three components: axial (along beam), lateral (perpendicular to beam in scan plane), and elevational (perpendicular to beam in the slice thickness direction).", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Image Quality" },
  { id: "sono-524", stem: "Axial resolution is determined primarily by:", options: ["Spatial pulse length (shorter pulses = better axial resolution)","Beam width","Transducer aperture size","Depth setting"], correctIndex: 0, rationale: "Axial resolution = SPL/2. Shorter spatial pulse length (achieved with higher frequency and fewer cycles per pulse) improves axial resolution. It is the best resolution in ultrasound imaging.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Image Quality" },
  { id: "sono-525", stem: "Lateral resolution is improved by:", options: ["Focusing the beam to narrow the beam width at the focal zone","Increasing the number of cycles per pulse","Decreasing the transducer frequency","Using a wider aperture with no focusing"], correctIndex: 0, rationale: "Lateral resolution depends on beam width. Focusing (electronic or mechanical) narrows the beam at the focal point, improving lateral resolution at that depth.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Image Quality" },
  { id: "sono-526", stem: "Harmonic imaging reduces artifacts because:", options: ["Harmonic frequencies are generated within tissue, avoiding body wall distortion and reducing clutter","It uses lower frequencies for deeper penetration","It eliminates all reflection artifacts","It increases fundamental frequency transmission"], correctIndex: 0, rationale: "Harmonic frequencies are generated progressively as the beam travels through tissue. The harmonic signal avoids the body wall artifacts and reverberation that affect the fundamental frequency.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-527", stem: "Compound imaging improves image quality by:", options: ["Acquiring data from multiple steering angles and averaging them to reduce speckle and improve border definition","Using a single beam angle with higher frequency","Increasing PRF","Decreasing dynamic range"], correctIndex: 0, rationale: "Spatial compound imaging steers the beam at multiple angles, averaging returning data. This reduces speckle, improves contrast resolution, and better defines tissue interfaces.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-528", stem: "Elastography in ultrasound assesses:", options: ["Tissue stiffness, which can help differentiate benign from malignant lesions","Blood flow velocity","Tissue temperature","Acoustic impedance"], correctIndex: 0, rationale: "Elastography measures tissue stiffness (strain or shear wave). Malignant lesions tend to be stiffer than benign tissue. Used in liver fibrosis, thyroid, breast, and prostate assessment.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-529", stem: "The normal pancreas on ultrasound appears:", options: ["Isoechoic to slightly hyperechoic compared to liver, becoming more echogenic with age due to fatty replacement","Always hypoechoic to the liver","Anechoic","Calcified with shadowing"], correctIndex: 0, rationale: "Normal pancreas is isoechoic to slightly brighter than liver. With age, fatty infiltration causes increased echogenicity. The pancreatic duct should measure ≤2mm.", difficulty: 2, category: "Abdominal Sonography", topic: "Pancreas" },
  { id: "sono-530", stem: "Acute pancreatitis on ultrasound may show:", options: ["Enlarged, hypoechoic pancreas with peripancreatic fluid collections","Small, hyperechoic pancreas","Normal pancreas in all cases","Calcified pancreas with shadowing"], correctIndex: 0, rationale: "Acute pancreatitis: diffuse or focal pancreatic enlargement, decreased echogenicity (edema), peripancreatic fluid, possible pseudocyst formation. CT is the primary imaging modality.", difficulty: 2, category: "Abdominal Sonography", topic: "Pancreas" },
  { id: "sono-531", stem: "The normal spleen measures:", options: ["Up to 12cm in length","Up to 20cm in length","Less than 5cm","Greater than 15cm is normal"], correctIndex: 0, rationale: "Normal spleen is up to 12cm in length (some use 13cm). Splenomegaly causes include portal hypertension, infection, hematologic disorders, and infiltrative diseases.", difficulty: 1, category: "Abdominal Sonography", topic: "Spleen" },
  { id: "sono-532", stem: "An abdominal aortic aneurysm (AAA) is defined as aortic diameter exceeding:", options: ["3.0cm","2.0cm","5.0cm","1.5cm"], correctIndex: 0, rationale: "AAA is defined as aortic diameter ≥3.0cm (or >1.5× normal diameter). Surgical repair is typically recommended at ≥5.5cm for men, ≥5.0cm for women, or growth >1cm/year.", difficulty: 1, category: "Vascular Sonography", topic: "Aortic Pathology" },
  { id: "sono-533", stem: "The ankle-brachial index (ABI) is used to:", options: ["Screen for and quantify peripheral arterial disease in the lower extremities","Measure venous reflux","Assess cardiac output","Evaluate carotid stenosis"], correctIndex: 0, rationale: "ABI = highest ankle systolic pressure / highest brachial systolic pressure. Normal ABI is 1.0-1.3. ABI <0.9 indicates PAD. ABI >1.3 suggests calcified, non-compressible vessels.", difficulty: 1, category: "Vascular Sonography", topic: "Lower Extremity Arterial" },
  { id: "sono-534", stem: "A Baker's cyst is located:", options: ["In the popliteal fossa, posterior to the knee","Anterior to the patella","In the inguinal region","Behind the ankle"], correctIndex: 0, rationale: "Baker's cyst (popliteal cyst) arises from the gastrocnemius-semimembranosus bursa in the posterior knee. It communicates with the knee joint and appears as a well-defined anechoic structure.", difficulty: 1, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-535", stem: "Ultrasound-guided procedures require:", options: ["Real-time visualization of the needle tip to ensure accurate and safe placement","Only pre-procedure imaging without real-time guidance","MRI correlation in all cases","CT guidance simultaneously"], correctIndex: 0, rationale: "Real-time ultrasound guidance allows continuous visualization of needle trajectory and tip position relative to the target and adjacent structures, improving accuracy and reducing complications.", difficulty: 1, category: "Patient Care & Safety", topic: "Interventional Procedures" },
  { id: "sono-536", stem: "A comet-tail artifact is a type of:", options: ["Reverberation artifact that appears as a bright echogenic focus with V-shaped echoes trailing posteriorly","Shadowing artifact","Enhancement artifact","Refraction artifact"], correctIndex: 0, rationale: "Comet-tail artifact is a short-path reverberation between closely spaced highly reflective interfaces. Seen with cholesterol crystals, metallic objects, and air bubbles.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Artifacts" },
  { id: "sono-537", stem: "Ring-down artifact appears as:", options: ["A continuous band of echoes trailing posterior to trapped air/gas","A single bright echo with shadow","An area of decreased echogenicity","A curved bright line"], correctIndex: 0, rationale: "Ring-down artifact produces a continuous streak of echoes from trapped gas between fluid layers. The bubbly structure resonates, producing a continuous sound wave that creates the artifact.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Artifacts" },
  { id: "sono-538", stem: "Side lobe artifacts can cause:", options: ["False echoes within cystic structures from off-axis reflections","Posterior acoustic shadowing","Enhanced through-transmission","Mirroring of structures"], correctIndex: 0, rationale: "Side lobes are low-intensity beams peripheral to the main beam. Strong reflectors in the side lobe path can create false echoes that appear in the main beam image, particularly within cysts.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Artifacts" },
  { id: "sono-539", stem: "The speed of sound in soft tissue assumed by ultrasound machines is:", options: ["1,540 m/s","1,000 m/s","330 m/s","3,000 m/s"], correctIndex: 0, rationale: "Ultrasound machines assume 1,540 m/s for soft tissue to calculate depth from echo return time. Actual speed varies: fat ~1,450 m/s, muscle ~1,580 m/s. Variance causes range errors.", difficulty: 1, category: "Ultrasound Physics & Instrumentation", topic: "Sound Propagation" },
  { id: "sono-540", stem: "Increasing the frequency of the ultrasound transducer results in:", options: ["Better axial resolution but decreased depth of penetration","Worse axial resolution with better penetration","No change in resolution or penetration","Better penetration with worse lateral resolution"], correctIndex: 0, rationale: "Higher frequency = shorter wavelength = better axial resolution, but higher attenuation = decreased penetration. This is the fundamental frequency-resolution-penetration tradeoff.", difficulty: 1, category: "Ultrasound Physics & Instrumentation", topic: "Sound Propagation" },
  { id: "sono-541", stem: "The Doppler angle should ideally be:", options: ["60 degrees or less for accurate velocity measurements","90 degrees for maximum sensitivity","Greater than 80 degrees","Exactly 45 degrees in all cases"], correctIndex: 0, rationale: "Doppler angle ≤60° provides acceptable accuracy. At angles >60°, small angle errors cause large velocity errors (cos function). At 90°, no Doppler shift is detected.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Principles" },
  { id: "sono-542", stem: "Spectral broadening in Doppler imaging indicates:", options: ["Disturbed or turbulent flow with a wider range of velocities present in the sample volume","Laminar flow","Technical error","Normal venous flow pattern"], correctIndex: 0, rationale: "Spectral broadening (filling in of the spectral window) indicates a range of velocities in the sample volume, caused by turbulence, stenosis, or a large sample volume.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Doppler Principles" },
  { id: "sono-543", stem: "A nuchal translucency measurement is performed at:", options: ["11-14 weeks gestational age to screen for chromosomal abnormalities","6-8 weeks","18-22 weeks","30-34 weeks"], correctIndex: 0, rationale: "NT measurement at 11-14 weeks (CRL 45-84mm) screens for trisomy 21, 18, 13 and other abnormalities. Increased NT (>3mm) warrants further genetic evaluation.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester Screening" },
  { id: "sono-544", stem: "A complete molar pregnancy on ultrasound shows:", options: ["'Snowstorm' pattern with no identifiable fetus and enlarged uterus","Normal fetus with placental abnormality","Empty gestational sac","Normal twins"], correctIndex: 0, rationale: "Complete mole: enlarged uterus filled with echogenic tissue showing multiple small cystic spaces ('snowstorm' or 'cluster of grapes'), no fetal parts, markedly elevated beta-hCG.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-545", stem: "Uterine fibroids (leiomyomas) typically appear on ultrasound as:", options: ["Well-circumscribed solid masses with variable echogenicity and possible shadowing from calcification","Always cystic structures","Homogeneously hyperechoic masses","Structures that only occur in the cervix"], correctIndex: 0, rationale: "Fibroids are the most common uterine tumors. They vary in echogenicity (hypo- to hyperechoic), may be calcified with shadowing, and are classified by location: submucosal, intramural, subserosal.", difficulty: 1, category: "OB/GYN Sonography", topic: "Uterine Pathology" },
  { id: "sono-546", stem: "An endometrioma (chocolate cyst) typically appears as:", options: ["Homogeneous, low-level internal echoes ('ground glass' appearance) within the ovary","Completely anechoic like a simple cyst","Solid hyperechoic mass","Calcified mass with shadowing"], correctIndex: 0, rationale: "Endometriomas contain old blood products giving a homogeneous 'ground glass' internal echo pattern. They may have wall nodularity. Associated with endometriosis and infertility.", difficulty: 2, category: "OB/GYN Sonography", topic: "Ovarian Pathology" },
  { id: "sono-547", stem: "Ovarian torsion ultrasound findings include:", options: ["Enlarged ovary with peripheral follicles, absent or decreased arterial flow on Doppler, and free fluid","Normal-sized ovary with normal flow","Small ovary with increased vascularity","Bilateral ovarian enlargement"], correctIndex: 0, rationale: "Ovarian torsion: unilateral ovarian enlargement (>5cm), peripherally displaced follicles, absent/decreased arterial flow, possible twisted pedicle (whirlpool sign), free fluid.", difficulty: 3, category: "OB/GYN Sonography", topic: "Ovarian Pathology" },
  { id: "sono-548", stem: "The normal endometrial thickness in a postmenopausal woman not on hormone therapy should be:", options: ["Less than or equal to 4-5mm","10-15mm","Greater than 8mm","20mm or more"], correctIndex: 0, rationale: "Normal postmenopausal endometrium (without HRT) should be ≤4-5mm. Thickening >4-5mm, especially with bleeding, requires further evaluation (endometrial biopsy) to exclude malignancy.", difficulty: 2, category: "OB/GYN Sonography", topic: "Uterine Pathology" },
  { id: "sono-549", stem: "A dermoid cyst (mature cystic teratoma) on ultrasound characteristically shows:", options: ["Fat-fluid level, echogenic component with shadowing (hair/teeth), and 'tip of the iceberg' sign","Purely anechoic simple cyst","Solid vascular mass","Multiple thin septations"], correctIndex: 0, rationale: "Dermoids contain ectodermal elements (hair, teeth, fat). Ultrasound shows echogenic mass with shadowing (Rokitansky nodule), fat-fluid levels, and dermoid mesh (hair). Most common benign ovarian tumor in young women.", difficulty: 2, category: "OB/GYN Sonography", topic: "Ovarian Pathology" },
  { id: "sono-550", stem: "Subclavian steal syndrome occurs when:", options: ["Proximal subclavian artery stenosis causes retrograde flow in the ipsilateral vertebral artery to supply the arm","The vertebral artery is occluded bilaterally","The internal carotid artery supplies the subclavian","The external carotid is stenosed"], correctIndex: 0, rationale: "Proximal subclavian stenosis/occlusion causes pressure drop distal to the lesion. Blood flows retrograde through the vertebral artery to supply the arm, potentially causing vertebrobasilar symptoms.", difficulty: 3, category: "Vascular Sonography", topic: "Vertebral/Subclavian" },
  { id: "sono-551", stem: "Venous reflux in the lower extremities is assessed by:", options: ["Augmentation with release (rapid deflation of manual compression), looking for retrograde flow lasting >0.5 seconds","Continuous compression of the limb","Assessment of arterial waveforms only","Palpation of pedal pulses"], correctIndex: 0, rationale: "Venous reflux is assessed with augmentation followed by release. Retrograde flow >0.5 seconds (>1 second in the femoral vein) indicates valvular incompetence. Performed in reverse Trendelenburg.", difficulty: 2, category: "Vascular Sonography", topic: "Lower Extremity Venous" },
  { id: "sono-552", stem: "A pseudoaneurysm (false aneurysm) on Doppler ultrasound shows:", options: ["'Yin-yang' or 'to-and-fro' flow pattern in a contained hematoma communicating with an artery through a tract","Normal arterial waveform","Absent flow","Venous waveform"], correctIndex: 0, rationale: "Pseudoaneurysm shows swirling 'yin-yang' flow in the contained hematoma and characteristic 'to-and-fro' waveform in the communicating neck. Often complicates arterial catheterization.", difficulty: 3, category: "Vascular Sonography", topic: "Arterial Pathology" },
  { id: "sono-553", stem: "The resistive index (RI) of a renal artery is calculated as:", options: ["(Peak systolic velocity - end diastolic velocity) / peak systolic velocity","Peak systolic velocity / end diastolic velocity","End diastolic velocity / peak systolic velocity","Peak systolic velocity × end diastolic velocity"], correctIndex: 0, rationale: "RI = (PSV - EDV) / PSV. Normal renal RI is <0.70. Elevated RI (>0.70) may indicate renal parenchymal disease, obstruction, or transplant rejection.", difficulty: 2, category: "Vascular Sonography", topic: "Renal Doppler" },
  { id: "sono-554", stem: "In renal artery stenosis, direct Doppler findings include:", options: ["Peak systolic velocity >200 cm/s at the stenosis and renal-to-aortic ratio >3.5","Decreased velocity at the stenosis","Normal velocity throughout","Reversed diastolic flow"], correctIndex: 0, rationale: "Significant renal artery stenosis (≥60%): PSV >200 cm/s, renal-aortic ratio (RAR) >3.5. Indirect signs include tardus-parvus waveform in intrarenal arteries (delayed upstroke, rounded peak).", difficulty: 3, category: "Vascular Sonography", topic: "Renal Doppler" },
  { id: "sono-555", stem: "A normal hepatic artery waveform shows:", options: ["Low-resistance flow with continuous forward diastolic flow","High-resistance flow with absent diastolic flow","Reversed flow in diastole","Monophasic venous-type flow"], correctIndex: 0, rationale: "The hepatic artery supplies a vascular bed with low peripheral resistance, resulting in continuous forward flow throughout the cardiac cycle (similar to ICA and renal arteries).", difficulty: 2, category: "Vascular Sonography", topic: "Hepatic Doppler" },
  { id: "sono-556", stem: "Portal hypertension is indicated when portal vein flow:", options: ["Is hepatofugal (away from the liver) or the portal vein is dilated >13mm","Is hepatopetal (toward the liver) with normal velocity","Shows increased velocity >30 cm/s","Is absent in all cases"], correctIndex: 0, rationale: "Portal hypertension signs: dilated portal vein (>13mm), slow flow (<16 cm/s), hepatofugal (reversed) flow, portosystemic collaterals (recanalized umbilical vein, splenorenal shunts), splenomegaly.", difficulty: 2, category: "Vascular Sonography", topic: "Portal Venous" },
  { id: "sono-557", stem: "The normal portal vein flow velocity is:", options: ["16-40 cm/s, hepatopetal (toward the liver)","60-100 cm/s","Less than 5 cm/s","Greater than 100 cm/s"], correctIndex: 0, rationale: "Normal portal vein flow is hepatopetal at 16-40 cm/s with gentle respiratory variation. Decreased velocity (<16 cm/s) or hepatofugal flow suggests portal hypertension.", difficulty: 2, category: "Vascular Sonography", topic: "Portal Venous" },
  { id: "sono-558", stem: "TIPS (transjugular intrahepatic portosystemic shunt) patency is assessed by:", options: ["Doppler showing flow velocities 90-190 cm/s within the stent and proper flow direction","Absence of flow within the stent","Reversed flow in the hepatic veins","Normal portal vein velocity without stent flow"], correctIndex: 0, rationale: "Normal TIPS stent velocities: 90-190 cm/s. Low velocity (<90) or high velocity (>190) suggests dysfunction. Absence of flow or reversed flow indicates occlusion.", difficulty: 4, category: "Vascular Sonography", topic: "Portal Venous" },
  { id: "sono-559", stem: "A carotid body tumor (paraganglioma) typically appears on ultrasound as:", options: ["A hypervascular solid mass at the carotid bifurcation that splays the ICA and ECA","An anechoic cyst posterior to the carotid","Thrombus within the carotid lumen","A calcified plaque at the bifurcation"], correctIndex: 0, rationale: "Carotid body tumors (chemodectomas) are hypervascular masses at the carotid bifurcation. They characteristically widen the angle between the ICA and ECA and show intense vascularity on color Doppler.", difficulty: 4, category: "Vascular Sonography", topic: "Carotid Pathology" },
  { id: "sono-560", stem: "Intussusception in pediatric patients on ultrasound shows:", options: ["'Target' or 'donut' sign on transverse view and 'pseudokidney' sign on longitudinal view","Normal bowel pattern","Free intraperitoneal air","Dilated loops without wall thickening"], correctIndex: 0, rationale: "Intussusception: target/donut sign (concentric rings of bowel in cross-section) and pseudokidney sign (longitudinal view). Most common in children 6-36 months. May require hydrostatic/pneumatic reduction.", difficulty: 2, category: "Abdominal Sonography", topic: "Pediatric" },
  { id: "sono-561", stem: "Pyloric stenosis in infants on ultrasound is diagnosed when:", options: ["Pyloric muscle thickness >3mm and channel length >15mm","Pyloric muscle thickness <1mm","Normal pyloric measurements","Dilated duodenum without pyloric changes"], correctIndex: 0, rationale: "Hypertrophic pyloric stenosis: muscle wall thickness >3mm, channel length >15mm, pyloric diameter >13mm. Clinical: non-bilious projectile vomiting in infants 2-8 weeks old.", difficulty: 2, category: "Abdominal Sonography", topic: "Pediatric" },
  { id: "sono-562", stem: "A transplant kidney is monitored by ultrasound primarily to:", options: ["Assess for rejection, vascular complications, hydronephrosis, and peritransplant fluid collections","Only measure kidney size","Screen for bladder cancer","Evaluate native kidney function"], correctIndex: 0, rationale: "Renal transplant ultrasound evaluates perfusion, resistive indices (elevated in rejection), hydronephrosis, peritransplant collections (hematoma, lymphocele, urinoma), and vascular complications (stenosis, thrombosis).", difficulty: 2, category: "Abdominal Sonography", topic: "Transplant" },
  { id: "sono-563", stem: "Budd-Chiari syndrome (hepatic vein thrombosis) on ultrasound shows:", options: ["Absent or reversed flow in hepatic veins, hepatomegaly, ascites, and caudate lobe hypertrophy","Normal hepatic vein flow","Dilated hepatic veins with normal flow","Portal vein thrombosis only"], correctIndex: 0, rationale: "Budd-Chiari: obstruction of hepatic venous outflow causing hepatomegaly, ascites, and caudate lobe hypertrophy (separate drainage). Doppler shows absent/reversed hepatic vein flow.", difficulty: 3, category: "Abdominal Sonography", topic: "Liver Vascular" },
  { id: "sono-564", stem: "The right adrenal gland is located:", options: ["Posterior to the IVC, superior to the right kidney, and lateral to the right crus of the diaphragm","Anterior to the left kidney","Inferior to the right kidney","Within the hepatic hilum"], correctIndex: 0, rationale: "The right adrenal is posterior to the IVC and superior-medial to the right kidney. It is best seen in sagittal and transverse planes using the liver as an acoustic window.", difficulty: 2, category: "Abdominal Sonography", topic: "Adrenal Glands" },
  { id: "sono-565", stem: "Contrast-enhanced ultrasound (CEUS) uses:", options: ["Microbubble contrast agents that are purely intravascular and enhance with harmonic imaging","Iodinated contrast agents","Gadolinium-based agents","Barium-based oral contrast"], correctIndex: 0, rationale: "CEUS uses gas-filled microbubbles (sulfur hexafluoride or perfluorocarbon) that remain intravascular, oscillate with ultrasound, and produce harmonic signals. Used for focal liver lesions, renal lesions, and more.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-566", stem: "Shear wave elastography provides:", options: ["Quantitative tissue stiffness measurements in kilopascals (kPa) or meters per second (m/s)","Only qualitative color maps without numeric values","Blood flow velocity measurements","Tissue temperature measurements"], correctIndex: 0, rationale: "Shear wave elastography (SWE) generates and measures shear wave speed, providing quantitative stiffness values. Used for liver fibrosis staging, breast and thyroid lesion characterization.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-567", stem: "When performing an ultrasound-guided biopsy, the needle is best visualized when:", options: ["The needle path is parallel to the transducer face (in-plane approach)","The needle is perpendicular to the beam","The needle is inserted without image guidance","The probe is removed before inserting the needle"], correctIndex: 0, rationale: "In-plane approach aligns the needle with the ultrasound beam plane, allowing visualization of the entire needle shaft and tip. Out-of-plane approach shows only a cross-section of the needle.", difficulty: 2, category: "Patient Care & Safety", topic: "Interventional Procedures" },
  { id: "sono-568", stem: "The pulsatility index (PI) is calculated as:", options: ["(Peak systolic velocity - end diastolic velocity) / time-averaged mean velocity","Peak systolic velocity / end diastolic velocity","Mean velocity / peak systolic velocity","End diastolic velocity × peak systolic velocity"], correctIndex: 0, rationale: "PI = (PSV - EDV) / mean velocity. PI reflects vascular resistance and pulsatility. Higher PI indicates greater resistance. Used in obstetric (umbilical artery) and cerebrovascular evaluation.", difficulty: 3, category: "Vascular Sonography", topic: "Hemodynamic Calculations" },
  { id: "sono-569", stem: "An echogenic liver mass with central hypoechoic scar and centrifugal arterial flow on Doppler is characteristic of:", options: ["Focal nodular hyperplasia (FNH)","Hepatocellular carcinoma","Hepatic metastasis","Hepatic hemangioma"], correctIndex: 0, rationale: "FNH: well-circumscribed mass with central stellate scar, spoke-wheel arterial pattern radiating from center. Benign lesion most common in young women, rarely requires treatment.", difficulty: 4, category: "Abdominal Sonography", topic: "Liver" },
  { id: "sono-570", stem: "The normal aortic diameter at the level of the renal arteries is:", options: ["Approximately 2.0cm or less","4.0cm","5.5cm","1.0cm"], correctIndex: 0, rationale: "Normal abdominal aorta is approximately 2.0cm at the level of the renal arteries, tapering to about 1.5cm at the bifurcation. Aortic diameter increases with age.", difficulty: 1, category: "Vascular Sonography", topic: "Aortic Assessment" },
  { id: "sono-571", stem: "A ICA occlusion on carotid duplex shows:", options: ["No detectable flow within the ICA lumen on B-mode, color, and spectral Doppler","High-velocity flow through the ICA","Normal flow with mild plaque","Reversed flow in the ICA"], correctIndex: 0, rationale: "Complete ICA occlusion: no color or spectral Doppler flow, possibly echogenic material filling the lumen. The ipsilateral CCA may show a high-resistance pattern ('externalization') and ECA may serve as collateral.", difficulty: 2, category: "Vascular Sonography", topic: "Carotid Doppler" },
  { id: "sono-572", stem: "When scanning the inferior mesenteric artery (IMA), the normal fasting waveform shows:", options: ["High-resistance flow with little or no diastolic flow","Low-resistance flow with prominent diastolic component","Continuous venous-type flow","No detectable flow at rest"], correctIndex: 0, rationale: "Like the SMA, the IMA shows high-resistance (little diastolic flow) in the fasting state. Postprandially, the mesenteric arteries convert to low-resistance patterns with increased diastolic flow.", difficulty: 3, category: "Vascular Sonography", topic: "Mesenteric Doppler" },
  { id: "sono-573", stem: "A sonographer discovers an incidental finding of possible malignancy during an examination. The appropriate action is to:", options: ["Complete the examination, document findings thoroughly, and ensure the interpreting physician is notified promptly","Inform the patient directly of the suspected diagnosis","Ignore the finding if it is outside the ordered exam scope","Post the findings on the PACS without notification"], correctIndex: 0, rationale: "Sonographers document findings but do not diagnose. Incidental findings should be thoroughly documented and communicated to the interpreting physician for timely evaluation and patient communication.", difficulty: 1, category: "Patient Care & Safety", topic: "Professional Standards" },
  { id: "sono-574", stem: "The diagnostic criteria for a simple ovarian cyst include:", options: ["Thin smooth walls, completely anechoic, round/oval, through-transmission, no internal echoes or septations","Thick irregular walls with solid components","Internal color Doppler flow","Mixed solid and cystic components"], correctIndex: 0, rationale: "Simple ovarian cysts are anechoic, have thin imperceptible walls, are round/oval, show posterior enhancement, and have no internal echoes, septations, or solid components. They are almost always benign.", difficulty: 1, category: "OB/GYN Sonography", topic: "Ovarian Pathology" },
  { id: "sono-575", stem: "The IUD (intrauterine device) on ultrasound appears as:", options: ["Bright echogenic linear structure within the endometrial cavity, often with posterior shadowing","Hypoechoic mass in the myometrium","Anechoic fluid collection","Cannot be visualized on ultrasound"], correctIndex: 0, rationale: "IUDs appear as echogenic structures in the uterine cavity. Copper IUDs show brighter echogenicity with shadowing. Position should be confirmed within the fundal endometrium. Malposition requires clinical assessment.", difficulty: 1, category: "OB/GYN Sonography", topic: "Uterine Assessment" },
  { id: "sono-576", stem: "Adenomyosis on ultrasound may show:", options: ["Asymmetric myometrial thickening, heterogeneous myometrium with myometrial cysts, and indistinct endometrial-myometrial junction","Well-circumscribed round mass","Calcified mass with shadowing","Normal myometrial appearance in all cases"], correctIndex: 0, rationale: "Adenomyosis (endometrial tissue within myometrium) shows diffuse or focal myometrial thickening, heterogeneous echotexture, small myometrial cysts, and obscured junctional zone. MRI is more specific.", difficulty: 3, category: "OB/GYN Sonography", topic: "Uterine Pathology" },
  { id: "sono-577", stem: "The most common location for an ectopic pregnancy is:", options: ["Ampullary portion of the fallopian tube","Isthmic portion of the fallopian tube","Ovary","Cervix"], correctIndex: 0, rationale: "About 95% of ectopics are tubal, and of those, approximately 70% are in the ampulla. Other locations include isthmus, fimbria, ovary, cervix, and abdomen.", difficulty: 2, category: "OB/GYN Sonography", topic: "Ectopic Pregnancy" },
  { id: "sono-578", stem: "The normal S/D ratio of the umbilical artery in the third trimester is:", options: ["Less than 3.0","Greater than 5.0","Equal to 1.0","Greater than 7.0"], correctIndex: 0, rationale: "Normal umbilical artery S/D ratio decreases throughout pregnancy as placental resistance decreases. In the third trimester, S/D should be <3.0. Elevated S/D, absent, or reversed diastolic flow indicates placental insufficiency.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-579", stem: "Absent end-diastolic flow in the umbilical artery is associated with:", options: ["Increased perinatal morbidity and mortality requiring urgent clinical evaluation","Normal fetal well-being","Improved placental function","No clinical significance"], correctIndex: 0, rationale: "Absent end-diastolic flow indicates severely elevated placental resistance and is associated with IUGR, fetal acidemia, and increased mortality. Reversed diastolic flow carries even worse prognosis.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Doppler" },
  { id: "sono-580", stem: "Twin-to-twin transfusion syndrome (TTTS) occurs in:", options: ["Monochorionic diamniotic twins with unbalanced arteriovenous anastomoses in the shared placenta","All twin pregnancies","Dichorionic twins only","Triplet pregnancies only"], correctIndex: 0, rationale: "TTTS occurs in monochorionic twins sharing a placenta with unbalanced vascular connections. The donor twin becomes growth-restricted with oligohydramnios; the recipient develops polyhydramnios and hydrops.", difficulty: 3, category: "OB/GYN Sonography", topic: "Multiple Gestation" },
  { id: "sono-581", stem: "Proper patient preparation for a pelvic ultrasound (transabdominal approach) requires:", options: ["A full urinary bladder to create an acoustic window and displace bowel gas","An empty bladder","No preparation needed","12-hour fasting"], correctIndex: 0, rationale: "A full bladder serves as an acoustic window to visualize pelvic structures. It displaces bowel gas and provides an anatomic reference. Patients drink 32oz water 1 hour before exam.", difficulty: 1, category: "Patient Care & Safety", topic: "Exam Preparation" },
  { id: "sono-582", stem: "A Grade III placenta (Grannum classification) shows:", options: ["Indentations extending to the basal plate creating cotyledons with central calcification","Smooth, homogeneous placental tissue","Small indentations not reaching the basal plate","No calcification"], correctIndex: 0, rationale: "Grade III: mature placenta with indentations through the full thickness creating cotyledons, basal plate calcification, and central calcification. Associated with term or post-term pregnancies.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Assessment" },
  { id: "sono-583", stem: "The SMA (superior mesenteric artery) in fasting state shows:", options: ["High-resistance waveform with sharp systolic peak and minimal diastolic flow","Low-resistance waveform with continuous diastolic flow","No detectable flow","Reversed diastolic flow normally"], correctIndex: 0, rationale: "Fasting SMA: high resistance with limited diastolic flow. Postprandially (30-60 minutes after eating): converts to low-resistance pattern with increased diastolic flow due to mesenteric vasodilation.", difficulty: 2, category: "Vascular Sonography", topic: "Mesenteric Doppler" },
  { id: "sono-584", stem: "Acute appendicitis on ultrasound is suggested when the appendix measures:", options: ["Greater than 6mm in diameter, is non-compressible, and shows periappendiceal inflammation","Less than 3mm in diameter","Greater than 15mm and compressible","Normal diameter with no surrounding changes"], correctIndex: 0, rationale: "Acute appendicitis criteria: outer diameter >6mm, non-compressible, blind-ending tubular structure, periappendiceal fat stranding/fluid, possible appendicolith. Graded compression technique is used.", difficulty: 2, category: "Abdominal Sonography", topic: "GI Tract" },
  { id: "sono-585", stem: "3D/4D ultrasound is particularly useful for:", options: ["Surface rendering of fetal face for cleft lip detection, uterine anomaly assessment, and volume measurements","Replacing all 2D scanning","Measuring blood flow velocity","All emergency examinations"], correctIndex: 0, rationale: "3D ultrasound provides surface rendering (facial anomalies), multiplanar imaging (uterine anomalies, IUD position), and volumetric measurements. 4D adds real-time to 3D. Supplements but does not replace 2D.", difficulty: 2, category: "Ultrasound Physics & Instrumentation", topic: "Advanced Techniques" },
  { id: "sono-586", stem: "The hepatorenal recess (Morison's pouch) is important in FAST exam because:", options: ["It is the most dependent peritoneal space in the supine patient where free fluid first accumulates","It is the least dependent space","It only contains bile","It is not visible on ultrasound"], correctIndex: 0, rationale: "Morison's pouch is the most dependent peritoneal space in supine patients. In FAST (Focused Assessment with Sonography in Trauma), free fluid here appears as an anechoic stripe between liver and kidney.", difficulty: 1, category: "Abdominal Sonography", topic: "FAST Exam" },
  { id: "sono-587", stem: "FAST exam standard views include:", options: ["Right upper quadrant, left upper quadrant, suprapubic, and subxiphoid/pericardial","Only the right upper quadrant","Bilateral kidneys and bladder only","Full abdominal survey with Doppler"], correctIndex: 0, rationale: "FAST: 4 views — RUQ (hepatorenal), LUQ (splenorenal), suprapubic (pelvic), and subxiphoid (pericardial). E-FAST adds bilateral anterior chest views for pneumothorax.", difficulty: 1, category: "Abdominal Sonography", topic: "FAST Exam" },
  { id: "sono-588", stem: "A choledochal cyst is:", options: ["A congenital cystic dilation of the bile duct system","A gallbladder polyp","A hepatic cyst","An adrenal cyst"], correctIndex: 0, rationale: "Choledochal cysts are congenital dilations of the biliary tree. Type I (most common) involves fusiform dilation of the CBD. Associated with increased risk of cholangiocarcinoma.", difficulty: 3, category: "Abdominal Sonography", topic: "Biliary System" },
  { id: "sono-589", stem: "The duty factor in pulsed ultrasound refers to:", options: ["The fraction of time the transducer is transmitting (pulse duration / pulse repetition period)","The total scanning time","The frame rate of the image","The attenuation coefficient"], correctIndex: 0, rationale: "Duty factor = PD/PRP × 100%. In imaging, it is very small (0.1-1%) as the transducer spends most time listening. In CW Doppler, duty factor is 50% (always transmitting and receiving).", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Pulsed Wave Concepts" },
  { id: "sono-590", stem: "Dynamic range in ultrasound refers to:", options: ["The range of echo amplitudes (weakest to strongest) that the system can display, measured in dB","The physical range of transducer movement","The depth of field","The frequency bandwidth"], correctIndex: 0, rationale: "Dynamic range is the ratio of the largest to smallest signal the system processes, typically 100-120 dB input, compressed to ~50 dB for display. Wider dynamic range shows more shades of gray.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Image Processing" },
  { id: "sono-591", stem: "Time gain compensation (TGC) is used to:", options: ["Compensate for attenuation by amplifying signals from deeper structures","Decrease overall image brightness","Reduce near-field artifacts","Increase transducer frequency"], correctIndex: 0, rationale: "TGC (depth gain compensation) applies increasing gain to deeper echo signals to compensate for tissue attenuation, creating uniform brightness throughout the image.", difficulty: 1, category: "Ultrasound Physics & Instrumentation", topic: "Image Optimization" },
  { id: "sono-592", stem: "A patient with right upper quadrant pain, jaundice, and fever (Charcot triad) should be evaluated for:", options: ["Ascending cholangitis","Simple cholecystitis","Renal colic","Appendicitis"], correctIndex: 0, rationale: "Charcot triad (RUQ pain, jaundice, fever) suggests ascending cholangitis — bacterial infection of the biliary tract usually caused by biliary obstruction. Reynolds pentad adds confusion and hypotension.", difficulty: 2, category: "Abdominal Sonography", topic: "Biliary Pathology" },
  { id: "sono-593", stem: "The normal testicular volume in an adult is:", options: ["12-20 mL","1-3 mL","30-40 mL","50 mL"], correctIndex: 0, rationale: "Normal adult testicular volume is 12-20 mL (varies by reference). Measured using the ellipsoid formula (L × W × H × 0.52). Size decreases with age and in conditions like Klinefelter syndrome.", difficulty: 2, category: "Small Parts & Superficial", topic: "Scrotal" },
  { id: "sono-594", stem: "Seminoma, the most common testicular malignancy, typically appears as:", options: ["Homogeneous, hypoechoic intratesticular mass","Hyperechoic mass with calcification","Cystic lesion with septations","Normal testicular echotexture"], correctIndex: 0, rationale: "Seminomas are the most common testicular germ cell tumors. They appear as well-defined, homogeneous, hypoechoic masses within the testis. Any solid intratesticular mass is malignant until proven otherwise.", difficulty: 2, category: "Small Parts & Superficial", topic: "Scrotal" },
  { id: "sono-595", stem: "A parathyroid adenoma on ultrasound typically appears as:", options: ["Hypoechoic, ovoid, well-defined mass posterior to the thyroid gland","Hyperechoic mass within the thyroid","Anechoic cyst anterior to the thyroid","Calcified mass with shadowing in the neck"], correctIndex: 0, rationale: "Parathyroid adenomas are typically hypoechoic, ovoid masses located posterior to the thyroid between the longus colli muscle and trachea. They are often hypervascular on color Doppler.", difficulty: 3, category: "Small Parts & Superficial", topic: "Parathyroid" },
  { id: "sono-596", stem: "Lymph nodes suspected of malignancy on ultrasound show:", options: ["Round shape (L/S ratio <2), loss of fatty hilum, irregular cortical thickening, and internal vascularity","Oval shape with preserved fatty hilum","Uniform cortical thickness <3mm","Central hilar vascularity only"], correctIndex: 0, rationale: "Suspicious lymph node features: round shape, absent fatty hilum, eccentric cortical thickening >3mm, peripheral or chaotic vascularity, microcalcifications, necrosis (cystic areas).", difficulty: 3, category: "Small Parts & Superficial", topic: "Lymph Nodes" },
  { id: "sono-597", stem: "A rotator cuff tear on musculoskeletal ultrasound appears as:", options: ["Focal hypoechoic or anechoic defect within the tendon with loss of normal fibrillar pattern","Increased tendon thickness without other changes","Normal tendon appearance","Calcification only"], correctIndex: 0, rationale: "Full-thickness tears show complete disruption of the tendon with anechoic/hypoechoic defect. Partial tears show focal thinning or hypoechoic defects. Dynamic scanning may show impingement.", difficulty: 2, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-598", stem: "De Quervain's tenosynovitis on ultrasound shows:", options: ["Thickening and hypoechogenicity of the first extensor compartment tendons with surrounding fluid","Normal tendon appearance","Calcification of the wrist joint","Fracture of the scaphoid"], correctIndex: 0, rationale: "De Quervain's affects the abductor pollicis longus and extensor pollicis brevis tendons. Ultrasound shows tendon thickening, hypoechoic changes, and peritendinous fluid in the first dorsal compartment.", difficulty: 3, category: "Small Parts & Superficial", topic: "Musculoskeletal" },
  { id: "sono-599", stem: "The AIUM (American Institute of Ultrasound in Medicine) output display standard requires:", options: ["Real-time display of Mechanical Index (MI) and Thermal Index (TI) on the ultrasound screen","Display of patient demographics only","No safety indices display","Only output power in watts"], correctIndex: 0, rationale: "AIUM ODS requires MI and TI displayed on screen when output exceeds specified thresholds. The sonographer monitors these indices to maintain ALARA principle and patient safety.", difficulty: 2, category: "Patient Care & Safety", topic: "Safety Standards" },
  { id: "sono-600", stem: "Posterior urethral valves in a male infant on ultrasound show:", options: ["Bilateral hydronephrosis, distended thick-walled bladder, and dilated posterior urethra ('keyhole' sign)","Normal urinary tract","Unilateral kidney enlargement only","Small contracted bladder"], correctIndex: 0, rationale: "PUV: the most common cause of severe obstructive uropathy in male infants. Prenatal ultrasound shows bilateral hydroureteronephrosis, dilated posterior urethra (keyhole sign), and thickened bladder wall.", difficulty: 3, category: "Abdominal Sonography", topic: "Pediatric" },
  { id: "sono-601", stem: "The AIUM recommends that ultrasound examinations be performed only by:", options: ["Qualified healthcare professionals with appropriate training and credentials","Anyone who can operate the equipment","Patients themselves for self-diagnosis","Administrative staff trained on-the-job"], correctIndex: 0, rationale: "AIUM guidelines state ultrasound should be performed by qualified professionals (RDMS, RDCS, RVT or equivalent). Training, continuing education, and appropriate credentialing ensure quality and safety.", difficulty: 1, category: "Patient Care & Safety", topic: "Professional Standards" },
  { id: "sono-602", stem: "Placental abruption on ultrasound may show:", options: ["Retroplacental or subchorionic hematoma, though ultrasound sensitivity is limited (25-60%)","Always a clearly visible collection","Normal placental appearance excludes abruption","Only intraplacental hemorrhage"], correctIndex: 0, rationale: "Placental abruption: premature separation of the placenta. Ultrasound may show retroplacental/marginal hematoma, but sensitivity is limited. Acute hemorrhage may be isoechoic to placenta. Clinical diagnosis often takes precedence.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-603", stem: "Cervical length measurement by transvaginal ultrasound is important for:", options: ["Predicting risk of preterm birth — length <25mm before 24 weeks is associated with increased risk","Measuring the uterine fundal height","Assessing ovarian follicle development","Diagnosing uterine fibroids"], correctIndex: 0, rationale: "Short cervix (<25mm before 24 weeks) is a strong predictor of spontaneous preterm birth. Transvaginal measurement is more accurate than transabdominal. Cervical cerclage or progesterone may be indicated.", difficulty: 2, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-604", stem: "Speckle reduction imaging works by:", options: ["Processing algorithms that reduce the granular texture (speckle) inherent in ultrasound images while preserving tissue boundaries","Increasing transducer frequency","Decreasing overall gain","Adding external contrast agents"], correctIndex: 0, rationale: "Speckle reduction uses post-processing algorithms to smooth granular texture noise from constructive/destructive interference patterns while maintaining edge definition and tissue boundary detail.", difficulty: 3, category: "Ultrasound Physics & Instrumentation", topic: "Image Processing" },
  { id: "sono-605", stem: "A sonographer's scope of practice includes:", options: ["Performing diagnostic ultrasound examinations, optimizing images, and providing preliminary findings to interpreting physicians","Diagnosing conditions and communicating diagnoses to patients","Ordering additional imaging studies independently","Prescribing medications based on findings"], correctIndex: 0, rationale: "Sonographers perform exams, optimize images, recognize pathology for preliminary findings, but do not diagnose or communicate diagnoses to patients. The interpreting physician makes the final diagnosis.", difficulty: 1, category: "Patient Care & Safety", topic: "Professional Standards" },
];
